SELECT D.line_material_id , D.production_line_id , D.production_line_name , D.production_line_status , D.daily_capacity , D.material_code FROM ( SELECT A.id AS line_material_id , B.id AS production_line_id , B.line_name AS production_line_name , B.status AS production_line_status , B.daily_capacity AS daily_capacity , C.material_code AS material_code , ROW_NUMBER() OVER (PARTITION BY C.material_code ORDER BY A.id) AS rn FROM line_material A INNER JOIN production_line B ON A.line_id = B.id INNER JOIN material C ON A.material_id = C.id WHERE C.material_code IN
#{code}
) D WHERE D.rn = 1
